function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const adj: [number, number, number][][] = Array.from({ length: n }, () => []);
    for (const [u, v, start, end] of edges) {
        adj[u].push([v, start, end]);
    }

    // Min-heap based on arrival time
    const heap: [number, number][] = [[0, 0]]; // [time, node]
    const dist: number[] = Array(n).fill(Infinity);
    dist[0] = 0;

    while (heap.length > 0) {
        heap.sort((a, b) => b[0] - a[0]); // Simple sort to simulate min-heap (not efficient for large n)
        const [currentTime, u] = heap.pop()!;

        if (u === n - 1) {
            return currentTime;
        }

        if (currentTime > dist[u]) {
            continue;
        }

        // Option to wait (but no need to push unless it helps)
        // Instead, explore edges from u
        for (const [v, start, end] of adj[u]) {
            // The earliest we can take this edge is max(currentTime, start)
            const earliestDeparture = Math.max(currentTime, start);
            if (earliestDeparture <= end) {
                const arrivalTime = earliestDeparture + 1;
                if (arrivalTime < dist[v]) {
                    dist[v] = arrivalTime;
                    heap.push([arrivalTime, v]);
                }
            }
        }
    }

    return dist[n - 1] !== Infinity ? dist[n - 1] : -1;
}
