function solve(n: number, edges: number[][]): number {
    // Build adjacency list
    const adj: [number, number, number][][] = new Array(n);
    for (let i = 0; i < n; i++) {
        adj[i] = [];
    }
    for (const [u, v, start, end] of edges) {
        adj[u].push([v, start, end]);
    }

    // Priority queue for Dijkstra's algorithm, sorted by time
    const heap: [number, number][] = []; // [time, node]
    heap.push([0, 0]);
    const visited = new Map<number, number>(); // node -> earliest arrival time
    visited.set(0, 0);

    while (heap.length > 0) {
        heap.sort((a, b) => a[0] - b[0]); // Sort to simulate a min-heap
        const [currentTime, u] = heap.shift()!;

        if (u === n - 1) {
            return currentTime;
        }

        for (const [v, start, end] of adj[u]) {
            // The earliest we can take this edge is max(currentTime, start)
            const departureTime = Math.max(currentTime, start);
            if (departureTime > end) {
                continue; // Edge is no longer available
            }
            const arrivalTime = departureTime + 1;

            if (!visited.has(v) || arrivalTime < visited.get(v)!) {
                visited.set(v, arrivalTime);
                heap.push([arrivalTime, v]);
            }
        }
    }

    return -1;
}
